import json
with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
changes = []
for k in sorted(set(list(b.keys()) + list(a.keys()))):
    bv = b.get(k, 'MISSING')
    av = a.get(k, 'MISSING')
    status = 'unchanged' if bv == av else 'CHANGED'
    print(f'{k[0]:20s} {k[1]:55s} {bv:10s} -> {av:10s} [{status}]')
    if status == 'CHANGED':
        changes.append(k)
if not changes:
    print('\nAll packages are version-neutral.')
"
", "description": "Compare resolved versions", "initial_wait": 10}

